{"code": "import json
import os

# Load NYSE non-ETF stocks
nyse_path = locals()['var_functions.query_db:24']
with open(nyse_path, 'r') as f:
    nyse_stocks = json.load(f)

symbol_to_company = {stock['Symbol']: stock['CompanyName'] for stock in nyse_stocks}
nyse_symbols = list(symbol_to_company.keys())

# Check if we have existing results to resume from
results_file = '/tmp/stock_analysis_results.json'
if os.path.exists(results_file):
    with open(results_file, 'r') as f:
        results = json.load(f)
    print('__RESULT__:')
    print(json.dumps({
        'status': 'resuming',
        'processed': len(results),
        'remaining': len(nyse_symbols) - len(results)
    }))
else:
    print('__RESULT__:')
    print(json.dumps({
        'status': 'starting fresh',
        'total_symbols': len(nyse_symbols)
    }))"}

{"code": "import json
import os

# Load NYSE non-ETF stocks
nyse_path = locals()['var_functions.query_db:24']
with open(nyse_path, 'r') as f:
    nyse_stocks = json.load(f)

symbol_to_company = {stock['Symbol']: stock['CompanyName'] for stock in nyse_stocks}
nyse_symbols = list(symbol_to_company.keys())

# Process each symbol
results = []
errors = []

for i, symbol in enumerate(nyse_symbols):
    try:
        # Query 2017 data for this symbol
        query = f"SELECT Date, Open, Close FROM \"{symbol}\" WHERE Date >= '2017-01-01' AND Date <= '2017-12-31'"

        # This is a placeholder - let's create a batch query approach instead
        results.append({
            'symbol': symbol,
            'company': symbol_to_company[symbol],
            'status': 'pending'
        })

    except Exception as e:
        errors.append({'symbol': symbol, 'error': str(e)})

# Save the structure
with open('/tmp/nyse_stocks_structure.json', 'w') as f:
    json.dump({
        'total_symbols': len(nyse_symbols),
        'results': results
    }, f)

print('__RESULT__:')
print(json.dumps({
    'message': 'Prepared structure for {} symbols'.format(len(nyse_symbols)),
    'total_symbols': len(nyse_symbols)
}))"}

